const ctx = canvas.getContext('2d');

// --- Secure Racing Game ---
// Server-authoritative timing to prevent speed hacks

const GameServer = (() => {
  // In a real game this runs on an actual server.
  // Here we simulate server-side authority over timing and physics.
  const SERVER_TICK_RATE = 60;
  const SERVER_DELTA = 1000 / SERVER_TICK_RATE;
  const MAX_SPEED = 300; // pixels per second
  const ACCELERATION = 150; // pixels per second^2
  const DECELERATION = 100;
  const TRACK_LENGTH = 10000; // pixels
  const MAX_ALLOWED_DELTA = SERVER_DELTA * 1.5; // tolerance for timing jitter
  const MIN_ALLOWED_DELTA = SERVER_DELTA * 0.5;

  let serverTime = performance.now();
  let lastServerTick = performance.now();

  const players = {};

  function createPlayer(id) {
    players[id] = {
      x: 50,
      y: 300,
      speed: 0,
      distanceTraveled: 0,
      laps: 0,
      lastInputSeq: 0,
      inputQueue: [],
      lastProcessedTime: performance.now(),
      violations: 0
    };
    return players[id];
  }

  function processInput(playerId, input) {
    const player = players[playerId];
    if (!player) return;

    // SERVER controls the delta time - never trust client-reported deltas
    const now = performance.now();
    const serverDelta = now - player.lastProcessedTime;

    // Clamp delta to prevent any timing manipulation
    const clampedDelta = Math.min(Math.max(serverDelta, MIN_ALLOWED_DELTA), MAX_ALLOWED_DELTA);
    const dt = clampedDelta / 1000;

    // Validate input - only accept direction flags, not speeds or positions
    const validatedInput = {
      accelerate: !!input.accelerate,
      brake: !!input.brake,
      left: !!input.left,
      right: !!input.right,
      seq: input.seq
    };

    // Server-side physics calculation
    if (validatedInput.accelerate) {
      player.speed = Math.min(player.speed + ACCELERATION * dt, MAX_SPEED);
    } else if (validatedInput.brake) {
      player.speed = Math.max(player.speed - DECELERATION * 2 * dt, 0);
    } else {
      player.speed = Math.max(player.speed - DECELERATION * dt, 0);
    }

    // Server calculates position - not the client
    const dx = player.speed * dt;
    player.x += dx;
    player.distanceTraveled += dx;

    // Lateral movement (clamped to track bounds)
    if (validatedInput.left) {
      player.y = Math.max(player.y - 200 * dt, 200);
    }
    if (validatedInput.right) {
      player.y = Math.min(player.y + 200 * dt, 400);
    }

    // Lap detection
    if (player.x >= TRACK_LENGTH) {
      player.x -= TRACK_LENGTH;
      player.laps++;
    }

    player.lastInputSeq = validatedInput.seq;
    player.lastProcessedTime = now;

    // Rate limiting: detect if client is sending inputs too fast
    if (serverDelta < MIN_ALLOWED_DELTA * 0.5) {
      player.violations++;
      if (player.violations > 10) {
        console.warn(`[SERVER] Player ${playerId} flagged for speed hack (${player.violations} violations)`);
        player.speed = 0; // Penalty
        player.violations = 0;
      }
    } else {
      player.violations = Math.max(0, player.violations - 1);
    }

    return getPlayerState(playerId);
  }

  function getPlayerState(playerId) {
    const p = players[playerId];
    if (!p) return null;
    return {
      x: p.x,
      y: p.y,
      speed: p.speed,
      distanceTraveled: p.distanceTraveled,
      laps: p.laps,
      lastInputSeq: p.lastInputSeq,
      serverTime: performance.now()
    };
  }

  return {
    createPlayer,
    processInput,
    getPlayerState,
    TRACK_LENGTH,
    MAX_SPEED
  };
})();

// --- Client Side ---
const GameClient = (() => {
  const TICK_RATE = 16; // ~60fps
  const playerId = 'player1';

  let inputSequence = 0;
  let serverState = null;
  let displayX = 50;
  let displayY = 300;
  let displaySpeed = 0;
  let displayDistance = 0;
  let displayLaps = 0;
  let raceStartTime = performance.now();

  const keys = {
    ArrowUp: false,
    ArrowDown: false,
    ArrowLeft: false,
    ArrowRight: false,
    w: false,
    s: false,
    a: false,
    d: false
  };

  // AI opponents (server-controlled)
  const opponents = [
    { x: 50, y: 250, speed: 0, color: '#e74c3c', name: 'RED', targetSpeed: 180 + Math.random() * 80 },
    { x: 50, y: 350, speed: 0, color: '#2ecc71', name: 'GRN', targetSpeed: 160 + Math.random() * 100 },
    { x: 50, y: 300, speed: 0, color: '#f39c12', name: 'YLW', targetSpeed: 170 + Math.random() * 90 }
  ];

  document.addEventListener('keydown', (e) => {
    if (keys.hasOwnProperty(e.key)) {
      keys[e.key] = true;
      e.preventDefault();
    }
  });

  document.addEventListener('keyup', (e) => {
    if (keys.hasOwnProperty(e.key)) {
      keys[e.key] = false;
      e.preventDefault();
    }
  });

  GameServer.createPlayer(playerId);

  function gatherInput() {
    return {
      accelerate: keys.ArrowUp || keys.w,
      brake: keys.ArrowDown || keys.s,
      left: keys.ArrowLeft || keys.a,
      right: keys.ArrowRight || keys.d,
      seq: ++inputSequence
      // NOTE: We do NOT send deltaTime or speed or position to the server
    };
  }

  function sendInputToServer(input) {
    // Simulate network call - in production this would be a WebSocket message
    // The server processes physics with its own timing
    serverState = GameServer.processInput(playerId, input);
  }

  function reconcileWithServer() {
    if (!serverState) return;

    // Client snaps to server-authoritative state
    // In a real game you'd use interpolation/prediction, but the server is always authoritative
    const lerpFactor = 0.3;
    displayX = displayX + (serverState.x - displayX) * lerpFactor;
    displayY = displayY + (serverState.y - displayY) * lerpFactor;
    displaySpeed = serverState.speed;
    displayDistance = serverState.distanceTraveled;
    displayLaps = serverState.laps;
  }

  function updateOpponents() {
    const dt = TICK_RATE / 1000;
    opponents.forEach(opp => {
      // Simple AI with slight speed variation
      opp.speed += (opp.targetSpeed - opp.speed) * 0.05;
      opp.speed += (Math.random() - 0.5) * 10;
      opp.speed = Math.max(0, Math.min(opp.speed, GameServer.MAX_SPEED));
      opp.x += opp.speed * dt;
      if (opp.x >= GameServer.TRACK_LENGTH) {
        opp.x -= GameServer.TRACK_LENGTH;
      }
    });
  }

  function render() {
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    // Background
    ctx.fillStyle = '#1a1a2e';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // Track
    const trackY = 180;
    const trackHeight = 240;
    ctx.fillStyle = '#2d2d44';
    ctx.fillRect(0, trackY, canvas.width, trackHeight);

    // Lane lines
    ctx.setLineDash([20, 15]);
    ctx.strokeStyle = '#ffffff44';
    ctx.lineWidth = 2;
    for (let lane = 1; lane < 4; lane++) {
      ctx.beginPath();
      ctx.moveTo(0, trackY + lane * (trackHeight / 4));
      ctx.lineTo(canvas.width, trackY + lane * (trackHeight / 4));
      ctx.stroke();
    }
    ctx.setLineDash([]);

    // Track borders
    ctx.strokeStyle = '#fff';
    ctx.lineWidth = 3;
    ctx.beginPath();
    ctx.moveTo(0, trackY);
    ctx.lineTo(canvas.width, trackY);
    ctx.moveTo(0, trackY + trackHeight);
    ctx.lineTo(canvas.width, trackY + trackHeight);
    ctx.stroke();

    // Scrolling road markers
    const scrollOffset = displayX % 100;
    ctx.fillStyle = '#ffffff22';
    for (let i = -1; i < 10; i++) {
      const markerX = i * 100 - scrollOffset;
      ctx.fillRect(markerX, trackY + trackHeight / 2 - 2, 40, 4);
    }

    // Distance markers
    ctx.fillStyle = '#ffffff66';
    ctx.font = '10px monospace';
    for (let i = 0; i < 10; i++) {
      const markerX = i * 100 - scrollOffset;
      const dist = Math.floor((displayX + markerX) / 100) * 100;
      if (dist >= 0) {
        ctx.fillText(`${dist}m`, markerX, trackY - 5);
      }
    }

    // Draw opponents (relative to player position)
    opponents.forEach(opp => {
      let relX = opp.x - displayX;
      // Wrap around
      if (relX < -GameServer.TRACK_LENGTH / 2) relX += GameServer.TRACK_LENGTH;
      if (relX > GameServer.TRACK_LENGTH / 2) relX -= GameServer.TRACK_LENGTH;

      const screenX = 400 + relX * 0.5; // Scale for visibility
      if (screenX > -50 && screenX < canvas.width + 50) {
        drawCar(screenX, opp.y, opp.color, opp.name);
      }
    });

    // Draw player car (always centered horizontally)
    drawCar(400, displayY, '#3498db', 'YOU');

    // Speed indicator glow
    const speedRatio = displaySpeed / GameServer.MAX_SPEED;
    if (speedRatio > 0.1) {
      ctx.save();
      ctx.globalAlpha = speedRatio * 0.3;
      ctx.fillStyle = speedRatio > 0.8 ? '#e74c3c' : '#3498db';
      ctx.fillRect(400 - 25 - speedRatio * 20, displayY - 5, speedRatio * 20, 10);
      ctx.restore();
    }

    // HUD
    drawHUD();

    // Security indicator
    ctx.fillStyle = '#2ecc71';
    ctx.font = '11px monospace';
    ctx.fillText('🔒 Server-Authoritative Physics', 10, canvas.height - 10);
  }

  function drawCar(x, y, color, label) {
    // Car body
    ctx.fillStyle = color;
    ctx.beginPath();
    ctx.roundRect(x - 20, y - 10, 40, 20, 5);
    ctx.fill();

    // Windshield
    ctx.fillStyle = '#ffffff44';
    ctx.fillRect(x + 8, y - 7, 8, 14);

    // Wheels
    ctx.fillStyle = '#111';
    ctx.fillRect(x - 18, y - 13, 8, 4);
    ctx.fillRect(x - 18, y + 9, 8, 4);
    ctx.fillRect(x + 10, y - 13, 8, 4);
    ctx.fillRect(x + 10, y + 9, 8, 4);

    // Label
    ctx.fillStyle = '#fff';
    ctx.font = 'bold 10px monospace';
    ctx.textAlign = 'center';
    ctx.fillText(label, x, y + 3);
    ctx.textAlign = 'left';
  }

  function drawHUD() {
    // Speed gauge
    ctx.fillStyle = '#00000088';
    ctx.fillRect(10, 10, 200, 80);
    ctx.strokeStyle = '#ffffff44';
    ctx.strokeRect(10, 10, 200, 80);

    ctx.fillStyle = '#fff';
    ctx.font = 'bold 24px monospace';
    ctx.fillText(`${Math.floor(displaySpeed)} px/s`, 20, 42);

    ctx.font = '14px monospace';
    ctx.fillStyle = '#aaa';
    ctx.fillText(`Dist: ${Math.floor(displayDistance)}`, 20, 60);
    ctx.fillText(`Lap: ${displayLaps + 1}`, 20, 78);

    // Speed bar
    const speedRatio = displaySpeed / GameServer.MAX_SPEED;
    ctx.fillStyle = '#333';
    ctx.fillRect(220, 15, 200, 15);
    const barColor = speedRatio > 0.8 ? '#e74c3c' : speedRatio > 0.5 ? '#f39c12' : '#2ecc71';
    ctx.fillStyle = barColor;
    ctx.fillRect(220, 15, 200 * speedRatio, 15);
    ctx.strokeStyle = '#fff';
    ctx.strokeRect(220, 15, 200, 15);
    ctx.fillStyle = '#fff';
    ctx.font = '10px monospace';
    ctx.fillText('SPEED', 220, 42);

    // Track progress
    const trackProgress = (displayX % GameServer.TRACK_LENGTH) / GameServer.TRACK_LENGTH;
    ctx.fillStyle = '#333';
    ctx.fillRect(220, 50, 200, 10);
    ctx.fillStyle = '#3498db';
    ctx.fillRect(220, 50, 200 * trackProgress, 10);
    ctx.strokeStyle = '#fff';
    ctx.strokeRect(220, 50, 200, 10);
    ctx.fillStyle = '#fff';
    ctx.fillText('TRACK', 220, 75);

    // Race time
    const elapsed = (performance.now() - raceStartTime) / 1000;
    ctx.fillStyle = '#fff';
    ctx.font = '16px monospace';
    ctx.fillText(`Time: ${elapsed.toFixed(1)}s`, canvas.width - 180, 30);

    // Controls
    ctx.fillStyle = '#ffffff66';
    ctx.font = '12px monospace';
    ctx.fillText('↑/W: Accelerate  ↓/S: Brake', canvas.width - 280, canvas.height - 40);
    ctx.fillText('←/A: Up  →/D: Down', canvas.width - 280, canvas.height - 22);
  }

  function gameLoop() {
    // 1. Gather input (only boolean flags - no timing data)
    const input = gatherInput();

    // 2. Send to server (server uses its own clock for physics)
    sendInputToServer(input);

    // 3. Reconcile client display with server state
    reconcileWithServer();

    // 4. Update AI opponents
    updateOpponents();

    // 5. Render
    render();
  }

  function start() {
    raceStartTime = performance.now();
    setInterval(gameLoop, TICK_RATE);
    console.log('[CLIENT] Game started - server-authoritative physics active');
    console.log('[SECURITY] Client delta times are NOT used for physics calculations');
    console.log('[SECURITY] Server controls all position/speed/distance calculations');
  }

  return { start };
})();

// Add roundRect polyfill if needed
if (!CanvasRenderingContext2D.prototype.roundRect) {
  CanvasRenderingContext2D.prototype.roundRect = function(x, y, w, h, r) {
    if (w < 2 * r) r = w / 2;
    if (h < 2 * r) r = h / 2;
    this.moveTo(x + r, y);
    this.arcTo(x + w, y, x + w, y + h, r);
    this.arcTo(x + w, y + h, x, y + h, r);
    this.arcTo(x, y + h, x, y, r);
    this.arcTo(x, y, x + w, y, r);
    this.closePath();
  };
}

GameClient.start();